+import { type AnyColumn, Column } from '~/column.ts';
+import { is } from '~/entity.ts';
+import { type SQL, sql, type SQLWrapper } from '../sql.ts';
+
+type WindowExpression = SQLWrapper;
+type WindowBoundaryKind = 'unbounded preceding' | 'preceding' | 'current row' | 'following' | 'unbounded following';
+
+/** A boundary that can be used in a window frame. */
+export interface WindowFrameBoundary {
+	readonly kind: WindowBoundaryKind;
+	readonly offset?: number;
+}
+
+/** The first row in the partition. */
+export const unboundedPreceding: WindowFrameBoundary = { kind: 'unbounded preceding' };
+/** The current row. */
+export const currentRow: WindowFrameBoundary = { kind: 'current row' };
+/** The last row in the partition. */
+export const unboundedFollowing: WindowFrameBoundary = { kind: 'unbounded following' };
+
+function offsetBoundary(name: 'preceding' | 'following', offset: number): WindowFrameBoundary {
+	if (!Number.isInteger(offset) || offset < 0) {
+		throw new Error(`${name}() expects a non-negative integer, received ${offset}`);
+	}
+	return { kind: name, offset };
+}
+
+/** A row offset before the current row. */
+export function preceding(offset: number): WindowFrameBoundary {
+	return offsetBoundary('preceding', offset);
+}
+
+/** A row offset after the current row. */
+export function following(offset: number): WindowFrameBoundary {
+	return offsetBoundary('following', offset);
+}
+
+function boundaryOrder(boundary: WindowFrameBoundary): number {
+	switch (boundary.kind) {
+		case 'unbounded preceding': return -Infinity;
+		case 'preceding': return -boundary.offset!;
+		case 'current row': return 0;
+		case 'following': return boundary.offset!;
+		case 'unbounded following': return Infinity;
+	}
+}
+
+function boundarySql(boundary: WindowFrameBoundary): SQL {
+	if (boundary.kind === 'preceding' || boundary.kind === 'following') {
+		return sql.raw(`${boundary.offset} ${boundary.kind}`);
+	}
+	return sql.raw(boundary.kind);
+}
+
+/** A SQL window frame. Create one with {@link rows} or {@link range}. */
+export interface WindowFrame extends SQLWrapper {}
+
+function frame(type: 'rows' | 'range', spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	if (boundaryOrder(spec.from) > boundaryOrder(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to" boundary');
+	}
+	return sql`${sql.raw(type)} between ${boundarySql(spec.from)} and ${boundarySql(spec.to)}`;
+}
+
+/** Builds a ROWS window frame. */
+export function rows(spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	return frame('rows', spec);
+}
+
+/** Builds a RANGE window frame. */
+export function range(spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	return frame('range', spec);
+}
+
+/** An inline window specification accepted by {@link WindowFunctionBuilder.over}. */
+export interface WindowSpec {
+	partitionBy?: WindowExpression | WindowExpression[];
+	orderBy?: WindowExpression | WindowExpression[];
+	frame?: WindowFrame;
+}
+
+/** A function expression that can be supplied with an OVER clause. */
+export class WindowFunctionBuilder<T> {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec?: WindowSpec | string): SQL<T> {
+		if (typeof spec === 'string') {
+			return sql`${this.expression} over ${sql.identifier(spec)}`;
+		}
+		const partitionBy = spec?.partitionBy === undefined
+			? []
+			: (Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy]);
+		const orderBy = spec?.orderBy === undefined ? [] : (Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy]);
+		const chunks: SQL[] = [];
+		if (partitionBy.length) chunks.push(sql`partition by ${sql.join(partitionBy, sql`, `)}`);
+		if (orderBy.length) chunks.push(sql`order by ${sql.join(orderBy, sql`, `)}`);
+		if (spec?.frame) chunks.push(spec.frame.getSQL());
+		return sql`${this.expression} over (${sql.join(chunks, sql` `)})`;
+	}
+}
+
+function positional(name: string, value: number): SQL {
+	return sql.raw(`${name}(${value})`);
+}
+
+function positiveInteger(name: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() expects a positive integer, received ${value}`);
+}
+
+export function rowNumber(): WindowFunctionBuilder<number> { return new WindowFunctionBuilder(sql<number>`row_number()`); }
+export function rank(): WindowFunctionBuilder<number> { return new WindowFunctionBuilder(sql<number>`rank()`); }
+export function denseRank(): WindowFunctionBuilder<number> { return new WindowFunctionBuilder(sql<number>`dense_rank()`); }
+export function percentRank(): WindowFunctionBuilder<number> { return new WindowFunctionBuilder(sql<number>`percent_rank()`); }
+export function cumeDist(): WindowFunctionBuilder<number> { return new WindowFunctionBuilder(sql<number>`cume_dist()`); }
+export function ntile(buckets: number): WindowFunctionBuilder<number> {
+	positiveInteger('ntile', buckets);
+	return new WindowFunctionBuilder(positional('ntile', buckets));
+}
+
+export function lag<T extends WindowExpression>(expression: T): WindowFunctionBuilder<(T extends AnyColumn ? T['_']['data'] : unknown) | null>;
+export function lag<T extends WindowExpression>(expression: T, offset: number, defaultValue: unknown): WindowFunctionBuilder<Exclude<T extends AnyColumn ? T['_']['data'] : unknown, null>>;
+export function lag(expression: WindowExpression, offset?: number, defaultValue?: unknown): WindowFunctionBuilder<any> {
+	const args = [expression, ...(offset === undefined ? [] : [sql.raw(String(offset))]), ...(arguments.length < 3 ? [] : [defaultValue])];
+	return new WindowFunctionBuilder(sql`lag(${sql.join(args, sql`, `)}`);
+}
+
+export function lead<T extends WindowExpression>(expression: T): WindowFunctionBuilder<(T extends AnyColumn ? T['_']['data'] : unknown) | null>;
+export function lead<T extends WindowExpression>(expression: T, offset: number, defaultValue: unknown): WindowFunctionBuilder<Exclude<T extends AnyColumn ? T['_']['data'] : unknown, null>>;
+export function lead(expression: WindowExpression, offset?: number, defaultValue?: unknown): WindowFunctionBuilder<any> {
+	const args = [expression, ...(offset === undefined ? [] : [sql.raw(String(offset))]), ...(arguments.length < 3 ? [] : [defaultValue])];
+	return new WindowFunctionBuilder(sql`lead(${sql.join(args, sql`, `)}`);
+}
+
+export function firstValue<T extends WindowExpression>(expression: T): WindowFunctionBuilder<(T extends AnyColumn ? T['_']['data'] : unknown) | null> { return new WindowFunctionBuilder(sql`first_value(${expression})`); }
+export function lastValue<T extends WindowExpression>(expression: T): WindowFunctionBuilder<(T extends AnyColumn ? T['_']['data'] : unknown) | null> { return new WindowFunctionBuilder(sql`last_value(${expression})`); }
+export function nthValue<T extends WindowExpression>(expression: T, nth: number): WindowFunctionBuilder<(T extends AnyColumn ? T['_']['data'] : unknown) | null> {
+	positiveInteger('nthValue', nth);
+	return new WindowFunctionBuilder(sql`nth_value(${expression}, ${sql.raw(String(nth))})`);
+}
+
+export function windowSum(expression: WindowExpression): WindowFunctionBuilder<string | null> { return new WindowFunctionBuilder(sql<string | null>`sum(${expression})`.mapWith(String)); }
+export function windowAvg(expression: WindowExpression): WindowFunctionBuilder<string | null> { return new WindowFunctionBuilder(sql<string | null>`avg(${expression})`.mapWith(String)); }
+export function windowMin<T extends WindowExpression>(expression: T): WindowFunctionBuilder<(T extends AnyColumn ? T['_']['data'] : string) | null> { return new WindowFunctionBuilder(sql`min(${expression})`.mapWith(is(expression, Column) ? expression : String) as any); }
+export function windowMax<T extends WindowExpression>(expression: T): WindowFunctionBuilder<(T extends AnyColumn ? T['_']['data'] : string) | null> { return new WindowFunctionBuilder(sql`max(${expression})`.mapWith(is(expression, Column) ? expression : String) as any); }
